import re

def detect_hallucination_regex(message):
    patterns = [
        r'\b(?:agent\.|autogen\.|vex_)\w*\(\)',  # Fake method calls
        r'(?:Microsoft|AutoGen)\s+(?:benchmarks?|paper|study)\s*(?:shows?|demonstrates?|achieved?)\s*\d{2,3}%',
        r'from\s+(?:autogen\.|vex_)[\w.]+\s+import',
        r'pip\s+install\s+(?:autogen-|vex-)\w+'
    ]
    return any(re.search(pattern, message, re.IGNORECASE) for pattern in patterns)

class ContextDriftDetector:
    def __init__(self):
        self.history = []

    def update(self, message):
        self.history.append(message)

    def detect_drift(self, message):
        message_words = set(message.lower().split())
        history_words = set(' '.join(self.history[-5:]).lower().split())  # Last 5 messages
        hallucinated_ratio = len(message_words - history_words) / len(message_words)
        return hallucinated_ratio > 0.6

import ast

def validate_autogen_code(code):
    try:
        tree = ast.parse(code)
        hallucinated_imports = [
            'vex_sdk', 'autogen.tools.hallucination', 'agent.execute_code',
            'GroupChatManager.terminate_now', 'autogen.benchmarks'
        ]
        for node in ast.walk(tree):
            if isinstance(node, ast.ImportFrom) and any(h in '.'.join([alias.name for alias in node.names]) for h in hallucinated_imports):
                return False
        return True
    except:
        return False

